"""Unit tests for the json_path_constraint module."""

import json
import unittest

from sglang.srt.constrained.json_path_constraint import (
    evaluate_json_path,
    json_path_to_schema,
    validate_json_path,
)


class TestValidateJsonPath(unittest.TestCase):
    """Tests for validate_json_path()."""

    def test_valid_root_only(self):
        validate_json_path("$")

    def test_valid_single_field(self):
        validate_json_path("$.name")

    def test_valid_nested_fields(self):
        validate_json_path("$.store.book")

    def test_valid_array_wildcard(self):
        validate_json_path("$.store.book[*]")

    def test_valid_array_index(self):
        validate_json_path("$.items[0]")

    def test_valid_complex_path(self):
        validate_json_path("$.store.book[*].author")

    def test_valid_underscore_and_hyphen_fields(self):
        validate_json_path("$.first_name")
        validate_json_path("$.my-field")

    def test_invalid_not_string(self):
        with self.assertRaises(ValueError):
            validate_json_path(123)  # type: ignore

    def test_invalid_no_dollar(self):
        with self.assertRaises(ValueError):
            validate_json_path("store.book")

    def test_invalid_recursive_descent(self):
        with self.assertRaises(ValueError):
            validate_json_path("$..name")

    def test_invalid_filter_expression(self):
        with self.assertRaises(ValueError):
            validate_json_path("$.store.book[?(@.price<10)]")

    def test_invalid_negative_index(self):
        with self.assertRaises(ValueError):
            validate_json_path("$.items[-1]")

    def test_invalid_wildcard_field(self):
        with self.assertRaises(ValueError):
            validate_json_path("$.*")

    def test_invalid_empty_field(self):
        with self.assertRaises(ValueError):
            validate_json_path("$.")

    def test_invalid_unmatched_bracket(self):
        with self.assertRaises(ValueError):
            validate_json_path("$.items[0")


class TestJsonPathToSchema(unittest.TestCase):
    """Tests for json_path_to_schema()."""

    def test_root_only(self):
        schema = json.loads(json_path_to_schema("$"))
        self.assertEqual(schema, {})

    def test_single_field(self):
        schema = json.loads(json_path_to_schema("$.name"))
        self.assertEqual(schema["type"], "object")
        self.assertIn("name", schema["properties"])
        self.assertEqual(schema["required"], ["name"])

    def test_nested_fields(self):
        schema = json.loads(json_path_to_schema("$.store.book"))
        self.assertEqual(schema["type"], "object")
        self.assertIn("store", schema["properties"])
        inner = schema["properties"]["store"]
        self.assertEqual(inner["type"], "object")
        self.assertIn("book", inner["properties"])
        self.assertEqual(inner["required"], ["book"])

    def test_array_wildcard(self):
        schema = json.loads(json_path_to_schema("$.items[*]"))
        self.assertEqual(schema["type"], "object")
        arr_schema = schema["properties"]["items"]
        self.assertEqual(arr_schema["type"], "array")

    def test_array_with_index(self):
        schema = json.loads(json_path_to_schema("$.items[0]"))
        arr_schema = schema["properties"]["items"]
        self.assertEqual(arr_schema["type"], "array")

    def test_complex_path(self):
        schema = json.loads(json_path_to_schema("$.store.book[*].author"))
        # $.store => object with "store"
        self.assertEqual(schema["type"], "object")
        store = schema["properties"]["store"]
        # .book => object with "book"
        self.assertEqual(store["type"], "object")
        book = store["properties"]["book"]
        # [*] => array
        self.assertEqual(book["type"], "array")
        # .author => items are objects with "author"
        items = book["items"]
        self.assertEqual(items["type"], "object")
        self.assertIn("author", items["properties"])
        self.assertEqual(items["required"], ["author"])

    def test_returns_valid_json_string(self):
        result = json_path_to_schema("$.a.b[*].c")
        # Must be parseable JSON
        parsed = json.loads(result)
        self.assertIsInstance(parsed, dict)


class TestEvaluateJsonPath(unittest.TestCase):
    """Tests for evaluate_json_path()."""

    def test_root(self):
        data = {"foo": "bar"}
        result = evaluate_json_path(data, "$")
        self.assertEqual(result, [{"foo": "bar"}])

    def test_single_field(self):
        data = {"name": "Alice"}
